import argparse
import boto3
import re
from urllib.parse import urlparse

def is_valid_https_url(url: str) -> bool:
    try:
        parsed = urlparse(url.strip())
        if parsed.scheme != "https":
            return False
        if not parsed.netloc:
            return False
        if re.search(r"[\r\n]", url):
            return False
        return True
    except Exception:
        return False

def subscribe_endpoint(sns_client, topic_arn: str, endpoint: str):
    return sns_client.subscribe(
        TopicArn=topic_arn,
        Protocol="https",
        Endpoint=endpoint,
        ReturnSubscriptionArn=True,
    )

def main():
    parser = argparse.ArgumentParser(description="Manage SNS HTTPS subscriptions safely.")
    parser.add_argument("--topic-arn", required=True, help="SNS topic ARN")
    parser.add_argument(
        "--endpoint",
        action="append",
        dest="endpoints",
        help="HTTPS endpoint to subscribe. Can be provided multiple times.",
    )
    parser.add_argument(
        "--region",
        default=None,
        help="AWS region name",
    )
    args = parser.parse_args()

    sns = boto3.client("sns", region_name=args.region) if args.region else boto3.client("sns")

    endpoints = list(args.endpoints or [])

    if not endpoints:
        print("Enter HTTPS endpoints, one per line. Submit an empty line to finish:")
